-- Turkish Voice Chat System - Client Side\nlocal QBCore = exports['qb-core']:GetCoreObject()\n\nlocal VoiceSettings = {\n    distance = 30.0,\n    enabled = true\n}\n\nCreateThread(function()\n    while VoiceSettings.enabled do\n        Wait(100)\n        for i = 0, 127 do\n            if i ~= PlayerId() then\n                local ped = PlayerPedId()\n                local targetPed = GetPlayerPed(i)\n                if targetPed ~= 0 then\n                    local distance = #(GetEntityCoords(ped) - GetEntityCoords(targetPed))\n                    if distance < VoiceSettings.distance then\n                        local volume = 1.0 - (distance / VoiceSettings.distance)\n                        MumbleSetVolumeOverride(GetPlayerFromServerId(i), volume)\n                    else\n                        MumbleSetVolumeOverride(GetPlayerFromServerId(i), 0.0)\n                    end\n                end\n            end\n        end\n    end\nend)\n\nprint('^2[Turkish Voice Chat] Yuklendi!^7')"